ruleSearch.bookList:
.grid tr!0
<js>
result.toArray().slice(0,10).map(o=>{
    var detail = String(o.select('td:eq(1) a').attr('href')).replace(/^\//, baseUrl.match(/(.+?\/\/[^\/]+\/)/)[1]);
    var J = org.jsoup.Jsoup.parse(java.ajax(detail));
    var oText = selector =>String(o.select(selector).text().trim()).replace(/.+：/, '');
    var jText = selector =>String(J.select(selector).text().trim()).replace(/.+：/, '');
    return {
       name:  oText('td:eq(1)'),
       author: oText('td:eq(2)'),
       tags:  [jText('.small:eq(4)'),jText('.small:eq(2)')].join(','),
       latest:  oText('td:eq(3)') +  oText('td:eq(4)').replace(/(\d+-\d+-\d+).*/,'（$1）'),
       intro: jText('.showInfo p'),
       cover: J.select('.detail_pic img').attr('src'),
       catalogUrl: J.select('.downButton').attr('href')
    }
}).filter(v =>v.name);
</js>
